<?php
namespace App\Domain\Hunts\Rewards\Data;use InvalidArgumentException;final class HuntRewardResult{private $v;private $items;public function __construct($id,$huntId,$sessionId,$status,$generatedAt,array $items){foreach($items as $item)if(!$item instanceof HuntRewardItemResult)throw new InvalidArgumentException();$this->v=func_get_args();$this->items=array_values($items);}public function rewardId(){return$this->v[0];}public function huntId(){return$this->v[1];}public function huntingSessionId(){return$this->v[2];}public function status(){return$this->v[3];}public function generatedAt(){return$this->v[4];}public function items(){return array_slice($this->items,0);}public function toArray(){$items=array_map(function($i){return$i->toArray();},$this->items);return['reward_id'=>$this->rewardId(),'hunt_id'=>$this->huntId(),'status'=>$this->status(),'has_items'=>count($items)>0,'item_lines_count'=>count($items),'total_quantity'=>array_sum(array_column($items,'quantity')),'items'=>$items];}}
